begin;
create extension if not exists pgtap with schema extensions;
select plan(35);
select has_table('public','districts','districts exists');select has_table('public','profiles','profiles exists');select has_table('public','dealers','dealers exists');select has_table('public','customers','customers exists');select has_table('public','customer_documents','customer documents exists');select has_table('public','price_lists','price lists exists');select has_table('public','price_list_items','price items exists');select has_table('public','quotations','quotations exists');select has_table('public','quotation_versions','quotation versions exists');select has_table('public','agreements','agreements exists');select has_table('public','projects','projects exists');select has_table('public','project_stage_history','project history exists');select has_table('public','inventory_items','inventory items exists');select has_table('public','stock_transactions','stock transactions exists');select has_table('public','purchase_invoices','purchase invoices exists');select has_table('public','dealer_commissions','commissions exists');select has_table('public','dealer_commission_payments','commission payments exists');select has_table('public','installation_materials','installation details exists');select has_table('public','customer_invoices','customer invoices exists');select has_table('public','audit_logs','audit log exists');select has_table('public','ai_extraction_logs','AI log exists');
select results_eq($$select enumlabel from pg_enum e join pg_type t on t.oid=e.enumtypid where t.typname='app_role' order by e.enumsortorder$$,$$values('admin'),('district_partner'),('dealer')$$,'exactly three business roles');
select has_function('public','save_customer',array['jsonb'],'secure customer RPC exists');select has_function('public','save_quotation_version',array['jsonb'],'quotation version RPC exists');select has_function('public','approve_quotation_and_create_project',array['uuid'],'atomic quotation/project RPC exists');select has_function('public','post_stock_transaction',array['jsonb'],'stock posting RPC exists');select has_function('public','post_purchase_invoice',array['jsonb'],'purchase posting RPC exists');select has_function('public','save_installation_and_issue_invoice',array['uuid','jsonb'],'invoice RPC exists');
select ok((select count(*)=0 from information_schema.role_table_grants where grantee='anon' and table_schema='public' and privilege_type in('SELECT','INSERT','UPDATE','DELETE')),'anon has no business table grants');
select ok((select bool_and(relrowsecurity) from pg_class c join pg_namespace n on n.oid=c.relnamespace where n.nspname='public' and c.relkind='r' and c.relname not in('schema_migrations')),'RLS enabled on every public business table');
select ok((select count(*)>0 from pg_policies where schemaname='public' and tablename='customers' and qual like '%can_access_customer%'),'customer access is scoped');
select ok((select count(*)=0 from pg_policies where schemaname='public' and tablename='projects' and coalesce(qual,'') like '%dealer%'),'Dealer has no project policy');
select ok((select count(*)>0 from pg_indexes where schemaname='public' and indexname='one_active_invoice_per_project'),'duplicate active invoice guard exists');
select ok((select count(*)>0 from pg_indexes where schemaname='public' and indexname='customer_mobile_active_uq'),'duplicate mobile guard exists');
select ok((select count(*)>0 from pg_indexes where schemaname='public' and indexname='customer_consumer_active_uq'),'duplicate consumer guard exists');
select * from finish();
rollback;
